(function (global) {
    "use strict";

    function asCanvas(target) {
        if (!target) return null;
        if (target instanceof HTMLCanvasElement) return target;
        if (target.canvas instanceof HTMLCanvasElement) return target.canvas;
        return null;
    }

    function themeColor(name, fallback) {
        var root = global.document && global.document.documentElement;
        if (!root || !global.getComputedStyle) return fallback;
        var value = global.getComputedStyle(root).getPropertyValue(name);
        return value ? value.trim() : fallback;
    }

    function roundedRect(ctx, x, y, w, h, r) {
        var radius = Math.max(0, Math.min(r || 0, Math.min(w, h) / 2));
        ctx.beginPath();
        ctx.moveTo(x + radius, y);
        ctx.arcTo(x + w, y, x + w, y + h, radius);
        ctx.arcTo(x + w, y + h, x, y + h, radius);
        ctx.arcTo(x, y + h, x, y, radius);
        ctx.arcTo(x, y, x + w, y, radius);
        ctx.closePath();
    }

    function clampText(label, maxLen) {
        if (String(label).length <= maxLen) return String(label);
        return String(label).slice(0, Math.max(0, maxLen - 1)) + "…";
    }

    function MiniChart(target, config) {
        this.canvas = asCanvas(target);
        if (!this.canvas) {
            throw new Error("Chart target must be a canvas element.");
        }

        this.ctx = this.canvas.getContext("2d");
        this.config = config || {};
        this._resizeHandler = this.draw.bind(this);
        global.addEventListener("resize", this._resizeHandler);
        this.draw();
    }

    MiniChart.prototype._fit = function () {
        var rect = this.canvas.getBoundingClientRect();
        var dpr = global.devicePixelRatio || 1;
        var width = Math.max(280, Math.floor(rect.width || this.canvas.clientWidth || 640));
        var height = Math.max(220, Math.floor(rect.height || this.canvas.clientHeight || 320));

        if (this.canvas.width !== Math.floor(width * dpr) || this.canvas.height !== Math.floor(height * dpr)) {
            this.canvas.width = Math.floor(width * dpr);
            this.canvas.height = Math.floor(height * dpr);
        }

        this.ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        this.width = width;
        this.height = height;
    };

    MiniChart.prototype._clear = function () {
        this.ctx.clearRect(0, 0, this.width, this.height);
    };

    MiniChart.prototype._drawNoData = function () {
        var ctx = this.ctx;
        ctx.save();
        ctx.fillStyle = themeColor("--muted", "#627d98");
        ctx.font = "600 14px Segoe UI";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.fillText("No data for chart", this.width / 2, this.height / 2);
        ctx.restore();
    };

    MiniChart.prototype.draw = function () {
        this._fit();
        this._clear();

        var type = (this.config.type || "").toLowerCase();
        if (type === "bar") {
            this._drawBar();
        } else if (type === "doughnut" || type === "donut") {
            this._drawDoughnut();
        } else {
            this._drawNoData();
        }
    };

    MiniChart.prototype._drawBar = function () {
        var ctx = this.ctx;
        var data = this.config.data || {};
        var labels = Array.isArray(data.labels) ? data.labels : [];
        var datasets = Array.isArray(data.datasets) ? data.datasets : [];

        if (!labels.length || !datasets.length) {
            this._drawNoData();
            return;
        }

        var left = 46;
        var right = 12;
        var top = 46;
        var bottom = 42;

        var plotW = this.width - left - right;
        var plotH = this.height - top - bottom;

        if (plotW <= 0 || plotH <= 0) {
            this._drawNoData();
            return;
        }

        var maxValue = 0;
        datasets.forEach(function (set) {
            (set.data || []).forEach(function (v) {
                var num = Number(v) || 0;
                if (num > maxValue) maxValue = num;
            });
        });

        if (maxValue <= 0) {
            this._drawNoData();
            return;
        }

        var gridSteps = 4;
        var yMax = Math.ceil(maxValue / gridSteps) * gridSteps;
        if (yMax < maxValue) yMax = maxValue;

        ctx.save();
        ctx.strokeStyle = themeColor("--chart-grid", "#dbe5ee");
        ctx.fillStyle = themeColor("--muted", "#627d98");
        ctx.lineWidth = 1;
        ctx.font = "12px Segoe UI";

        for (var i = 0; i <= gridSteps; i += 1) {
            var y = top + (plotH / gridSteps) * i;
            ctx.beginPath();
            ctx.moveTo(left, y);
            ctx.lineTo(left + plotW, y);
            ctx.stroke();

            var value = yMax - (yMax / gridSteps) * i;
            ctx.textAlign = "right";
            ctx.textBaseline = "middle";
            ctx.fillText(String(Math.round(value)), left - 6, y);
        }

        ctx.strokeStyle = themeColor("--chart-axis", "#c8d4df");
        ctx.beginPath();
        ctx.moveTo(left, top);
        ctx.lineTo(left, top + plotH);
        ctx.lineTo(left + plotW, top + plotH);
        ctx.stroke();

        var legendX = left;
        var legendY = 14;
        datasets.forEach(function (set, idx) {
            var color = set.backgroundColor || ["#15803d", "#c2410c", "#2563eb"][idx % 3];
            ctx.fillStyle = color;
            ctx.fillRect(legendX, legendY, 12, 12);
            ctx.fillStyle = themeColor("--chart-legend", "#334e68");
            ctx.textAlign = "left";
            ctx.textBaseline = "top";
            ctx.fillText(String(set.label || ("Series " + (idx + 1))), legendX + 18, legendY - 1);
            legendX += 110;
        });

        var groupCount = labels.length;
        var setCount = datasets.length;
        var groupWidth = plotW / groupCount;
        var barArea = groupWidth * 0.74;
        var barWidth = Math.max(8, Math.min(44, barArea / setCount));
        var groupPad = (groupWidth - barWidth * setCount) / 2;

        for (var li = 0; li < groupCount; li += 1) {
            for (var di = 0; di < setCount; di += 1) {
                var ds = datasets[di];
                var valueNum = Number((ds.data || [])[li]) || 0;
                var barH = (valueNum / yMax) * plotH;

                var x = left + li * groupWidth + groupPad + di * barWidth;
                var yBar = top + plotH - barH;

                ctx.fillStyle = ds.backgroundColor || ["#15803d", "#c2410c", "#2563eb"][di % 3];
                roundedRect(ctx, x + 1, yBar, barWidth - 2, barH, 5);
                ctx.fill();
            }

            ctx.fillStyle = themeColor("--muted", "#627d98");
            ctx.font = "11px Segoe UI";
            ctx.textAlign = "center";
            ctx.textBaseline = "top";
            ctx.fillText(clampText(labels[li], 9), left + li * groupWidth + groupWidth / 2, top + plotH + 8);
        }

        ctx.restore();
    };

    MiniChart.prototype._drawDoughnut = function () {
        var ctx = this.ctx;
        var data = this.config.data || {};
        var labels = Array.isArray(data.labels) ? data.labels : [];
        var dataset = (data.datasets && data.datasets[0]) || { data: [] };
        var values = Array.isArray(dataset.data) ? dataset.data : [];

        if (!labels.length || !values.length) {
            this._drawNoData();
            return;
        }

        var total = values.reduce(function (acc, v) {
            return acc + Math.max(0, Number(v) || 0);
        }, 0);

        if (total <= 0) {
            this._drawNoData();
            return;
        }

        var palette = Array.isArray(dataset.backgroundColor) && dataset.backgroundColor.length
            ? dataset.backgroundColor
            : ["#0f766e", "#c2410c", "#2563eb", "#0e7490", "#eab308", "#334155", "#15803d"];

        var cx = this.width > 520 ? this.width * 0.34 : this.width / 2;
        var cy = this.height / 2;
        var radius = Math.min(this.height * 0.32, this.width * (this.width > 520 ? 0.2 : 0.3));
        var inner = radius * 0.58;

        var start = -Math.PI / 2;
        for (var i = 0; i < values.length; i += 1) {
            var value = Math.max(0, Number(values[i]) || 0);
            var angle = (value / total) * Math.PI * 2;

            ctx.beginPath();
            ctx.moveTo(cx, cy);
            ctx.fillStyle = palette[i % palette.length];
            ctx.arc(cx, cy, radius, start, start + angle);
            ctx.closePath();
            ctx.fill();
            start += angle;
        }

        ctx.beginPath();
        ctx.fillStyle = themeColor("--surface", "#ffffff");
        ctx.arc(cx, cy, inner, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = themeColor("--ink", "#102a43");
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.font = "700 13px Segoe UI";
        ctx.fillText("Expense", cx, cy - 9);
        ctx.font = "700 16px Segoe UI";
        ctx.fillText("$" + total.toFixed(2), cx, cy + 11);

        ctx.font = "12px Segoe UI";
        ctx.textAlign = "left";
        ctx.textBaseline = "middle";

        var legendX = this.width > 520 ? this.width * 0.58 : 14;
        var legendY = this.width > 520 ? 34 : this.height - Math.min(22 * labels.length, this.height - 12);

        for (var li = 0; li < labels.length; li += 1) {
            var itemY = legendY + li * 20;
            if (itemY > this.height - 8) break;

            ctx.fillStyle = palette[li % palette.length];
            ctx.fillRect(legendX, itemY - 5, 10, 10);
            ctx.fillStyle = themeColor("--muted", "#486581");
            ctx.fillText(clampText(labels[li], 14) + "  $" + (Number(values[li]) || 0).toFixed(2), legendX + 16, itemY);
        }
    };

    global.Chart = MiniChart;
})(window);
